CREATE TABLE IF NOT EXISTS sales_documents(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),warehouse_id uuid NOT NULL REFERENCES warehouses(id)ON DELETE CASCADE,customer_id uuid NOT NULL REFERENCES partners(id),document_no text NOT NULL,kind text NOT NULL CHECK(kind IN('quote','order','invoice')),status text NOT NULL DEFAULT'draft'CHECK(status IN('draft','approved','converted','shipped','issued','cancelled')),source_document_id uuid REFERENCES sales_documents(id),outbound_document_id uuid REFERENCES stock_documents(id),snapshot jsonb NOT NULL DEFAULT'{}',created_by uuid REFERENCES users(id),created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(warehouse_id,document_no));
CREATE TABLE IF NOT EXISTS sales_document_lines(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),sales_document_id uuid NOT NULL REFERENCES sales_documents(id)ON DELETE CASCADE,product_id uuid NOT NULL REFERENCES products(id),quantity numeric(18,4)NOT NULL CHECK(quantity>0),unit_price numeric(18,4)NOT NULL CHECK(unit_price>=0),tax_rate numeric(7,4)NOT NULL DEFAULT 0 CHECK(tax_rate>=0));
CREATE INDEX IF NOT EXISTS idx_sales_scope ON sales_documents(warehouse_id,kind,status,created_at DESC);
